import { useState, useEffect } from "react";
import axios from "axios";

const API = "http://localhost:5000";

export default function App() {
  const [token, setToken] = useState(localStorage.getItem("token"));
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [items, setItems] = useState([]);
  const [name, setName] = useState("");

  const login = async () => {
    const res = await axios.post(`${API}/api/login`, { email, password });
    localStorage.setItem("token", res.data.token);
    setToken(res.data.token);
  };

  const register = async () => {
    await axios.post(`${API}/api/register`, {
      name: "User",
      email,
      password
    });
    alert("Registered Successfully");
  };

  const addItem = async () => {
    await axios.post(
      `${API}/api/items`,
      { name },
      { headers: { Authorization: token } }
    );
    fetchItems();
    setName("");
  };

  const fetchItems = async () => {
    const res = await axios.get(`${API}/api/items`, {
      headers: { Authorization: token }
    });
    setItems(res.data);
  };

  useEffect(() => {
    if (token) fetchItems();
  }, [token]);

  // 🔐 LOGIN UI
  if (!token) {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <h2>Lost & Found</h2>

          <input
            style={styles.input}
            placeholder="Email"
            onChange={(e) => setEmail(e.target.value)}
          />

          <input
            style={styles.input}
            type="password"
            placeholder="Password"
            onChange={(e) => setPassword(e.target.value)}
          />

          <button style={styles.primary} onClick={login}>
            Login
          </button>

          <button style={styles.secondary} onClick={register}>
            Register
          </button>
        </div>
      </div>
    );
  }

  // 📊 DASHBOARD UI
  return (
    <div style={styles.container}>
      <div style={styles.dashboard}>
        <div style={styles.header}>
          <h2>Dashboard</h2>
          <button
            style={styles.logout}
            onClick={() => {
              localStorage.clear();
              setToken(null);
            }}
          >
            Logout
          </button>
        </div>

        <div style={styles.addBox}>
          <input
            style={styles.input}
            placeholder="Item Name"
            value={name}
            onChange={(e) => setName(e.target.value)}
          />
          <button style={styles.primary} onClick={addItem}>
            Add Item
          </button>
        </div>

        <div style={styles.list}>
          {items.map((item) => (
            <div key={item._id} style={styles.item}>
              {item.name}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// 🎨 STYLES
const styles = {
  container: {
    height: "100vh",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    background: "#eef2f7"
  },
  card: {
    width: "320px",
    padding: "25px",
    background: "#fff",
    borderRadius: "10px",
    boxShadow: "0 4px 20px rgba(0,0,0,0.1)",
    textAlign: "center"
  },
  dashboard: {
    width: "400px",
    padding: "20px",
    background: "#fff",
    borderRadius: "10px",
    boxShadow: "0 4px 20px rgba(0,0,0,0.1)"
  },
  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center"
  },
  input: {
    width: "100%",
    padding: "10px",
    margin: "10px 0",
    borderRadius: "6px",
    border: "1px solid #ccc"
  },
  primary: {
    width: "100%",
    padding: "10px",
    background: "#4CAF50",
    color: "#fff",
    border: "none",
    borderRadius: "6px",
    cursor: "pointer",
    marginTop: "10px"
  },
  secondary: {
    width: "100%",
    padding: "10px",
    background: "#2196F3",
    color: "#fff",
    border: "none",
    borderRadius: "6px",
    cursor: "pointer",
    marginTop: "10px"
  },
  logout: {
    padding: "5px 10px",
    background: "red",
    color: "#fff",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer"
  },
  addBox: {
    marginTop: "15px"
  },
  list: {
    marginTop: "20px"
  },
  item: {
    padding: "10px",
    background: "#f4f4f4",
    marginTop: "5px",
    borderRadius: "5px"
  }
};
